export default function Loader() {
  return (
    <div className="flex items-center justify-center h-screen bg-black">
      <div className="relative w-40 h-40">
        {/* Outer ring */}
        <div className="absolute inset-0 rounded-full border border-white/30"></div>

        {/* Rotating orbit dots */}
        <div className="absolute inset-0 animate-spin">
          <div className="absolute top-0 left-1/2 w-2 h-2 bg-white rounded-full -translate-x-1/2"></div>
          <div className="absolute bottom-0 left-1/2 w-2 h-2 bg-white/70 rounded-full -translate-x-1/2"></div>
        </div>

        {/* Glow effect */}
        <div className="absolute inset-2 rounded-full bg-gradient-to-br from-purple-500 via-pink-500 to-blue-500 blur-2xl opacity-50"></div>

        {/* Main orb */}
        <div className="absolute inset-4 rounded-full bg-gradient-to-br from-purple-600 via-pink-500 to-blue-600 flex items-center justify-center backdrop-blur-xl">
          {/* Inner glass reflection */}
          <div className="absolute inset-0 rounded-full bg-white/10 backdrop-blur-md"></div>

          {/* Highlight */}
          <div className="absolute top-4 left-4 w-12 h-12 bg-white/20 rounded-full blur-xl"></div>
        </div>
      </div>
    </div>
  );
}
